const cartItems=document.querySelectorAll(".cart-item"),caddieCount=document.getElementById("caddie-count");async function updateItem(e,t){try{const a=await fetch("../back/router.php?action=update-caddie",{method:"PATCH",headers:{"Content-Type":"application/json","X-CSRF-TOKEN":getCsrfToken()},body:JSON.stringify({productId:e,quantity:t})}),n=await a.json();n.success?(updatePrice(n),caddieCount.textContent=n.count):showNotification(n.message,"red")}catch(e){console.error(e)}}function updatePrice(e){document.getElementById("total").textContent=`${e.total} €`,document.getElementById("delivery").textContent=0===e.delivery?"Offerte":`${e.delivery} €`,document.getElementById("finalTotal").textContent=`${e.finalTotal} €`,e.total>=50?document.getElementById("comment").textContent="":document.getElementById("comment").textContent=`Plus que ${e.deliveryMissing} € pour la livraison offerte.`}cartItems.forEach(e=>{const t=e.querySelector(".qty"),a=e.querySelector(".add"),n=e.querySelector(".decrease"),o=parseInt(t.max);a.addEventListener("click",()=>{let a=parseInt(t.value);a<o&&(t.value=a+1,updateItem(e.dataset.id,t.value))}),n.addEventListener("click",()=>{let a=parseInt(t.value);a>1&&(t.value=a-1,updateItem(e.dataset.id,t.value))}),t.addEventListener("change",()=>{let a=parseInt(t.value);a<1&&(a=1),a>o&&(a=o),t.value=a,updateItem(e.dataset.id,a)})}),document.querySelectorAll(".cart-item__delete").forEach(e=>{e.addEventListener("click",async()=>{const t=e.dataset.id,a=await fetch("../back/router.php?action=delete-caddie",{method:"DELETE",headers:{"Content-Type":"application/json","X-CSRF-TOKEN":getCsrfToken()},body:JSON.stringify({productId:t})}),n=await a.json();if(n.success){const e=document.querySelector(`.cart-item[data-id="${t}"]`);e&&e.remove(),updatePrice(n),caddieCount.textContent=n.count,0===document.querySelectorAll(".cart-item").length&&(document.querySelector(".cart-page").innerHTML='\n                    <h1 class="shop-page__title">Mon panier</h1>\n                    <section class="container page-404">\n                        <p class="page-404__label">Votre panier est vide.</p>\n                        <a href="../back/router.php?action=shop-view" class="page-404__cta">Aller à la boutique</a>\n                    </section>\';\n                '),showNotification("Produit supprimé du panier","green")}else showNotification(n.message,"red")})});